mapper.insert:
insert into sys_module (
    id, parent_id, ancestors, module_code, module_name, module_type, route_path, component_path, icon, sort,
    nav_visible, stateful_flag, state_field_code, context_version, status, create_by, create_time, update_by, update_time, note
) values (
    #{id}, #{parentId}, #{ancestors}, #{moduleCode}, #{moduleName}, #{moduleType}, #{routePath}, #{componentPath}, #{icon}, #{sort},
    #{navVisible}, #{statefulFlag}, #{stateFieldCode}, #{contextVersion}, #{status}, #{createBy}, #{createTime}, #{updateBy}, #{updateTime}, #{note}
)

mapper.update:
update sys_module
parent_id = #{parentId}, ancestors = #{ancestors}, module_code = #{moduleCode}, module_name = #{moduleName}, module_type = #{moduleType}, route_path = #{routePath}, component_path = #{componentPath}, icon = #{icon}, sort = #{sort}, nav_visible = #{navVisible}, stateful_flag = #{statefulFlag}, state_field_code = #{stateFieldCode}, context_version = #{contextVersion}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}, note = #{note},
where id = #{id}

mapper.select:
select 
from sys_module


        and parent_id = #{parentId}


        and module_code like concat('%', #{moduleCode}, '%')


        and module_name like concat('%', #{moduleName}, '%')


        and module_type = #{moduleType}


        and stateful_flag = #{statefulFlag}


        and status = #{status}


order by sort asc, id asc

select 
from sys_module
where id = #{id}

select count(1)
from sys_module
where parent_id = #{parentId}

mapper.update:
update sys_module
set ancestors = replace(ancestors, #{oldPath}, #{newPath}),
    update_time = #{updateTime}
where ancestors = #{oldPath}
   or ancestors like concat(#{oldPath}, ',%')

update sys_module
set context_version = ifnull(context_version, 0) + 1,
    update_time = #{updateTime}
where id = #{moduleId}

